import { useState, useEffect } from 'react';
import '../index.css';
import { useNavigate } from 'react-router-dom';

export function NavBarRecepcionar() {
  const navigate = useNavigate();
  const [userEmail, setUserEmail] = useState("");

  // Funkcija za čitanje cookie-a po imenu
  const getCookie = (name) => {
    const match = document.cookie.match(new RegExp('(^| )' + name + '=([^;]+)'));
    if (match) return decodeURIComponent(match[2]);
    return null;
  };

  // Proverava cookie kada se NavBar učita
  useEffect(() => {
    const email = getCookie("userEmail"); // ime cookie-a koji čuvaš pri login-u
    if (email) {
      setUserEmail(email);
    }
  }, []);

  const handleLogout = () => {
    document.cookie = "userEmail=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;";
    setUserEmail("");
    navigate("/");
  };

    return (
    <header>
      <nav
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          width: "100%",
          padding: "20px",
          background: "#af65c5"
        }}
      >
        {/* LEVA STRANA NAVBARA */}
        <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
          <span className="btnNav" onClick={() => navigate("/dodaj_sobu")}>
            Dodaj novu sobu
          </span>
          <input
            type="text"
            style={{
              width: "300px",
              height: "25px",
              fontSize: "18px",
              borderRadius: "8px",
              padding: "5px 10px",
            }}
          />
        </div>

        {/* DESNA STRANA NAVBARA */}
        <div style={{ display: "flex", gap: "10px" }}>
          {userEmail ? (
            <>
              <span className='btnNav' onClick={() => navigate("/pravljenje_rezervacije")}>
                Napravi rezervaciju
              </span>
              <span style={{ color: "white", fontSize: "16px", marginTop:"auto", marginBottom:"auto" }}>
                {userEmail}
              </span>
              <span className="btnNav" onClick={handleLogout}>Logout</span>
            </>
          ) : (
            <>
              <span className="btnNav" onClick={() => navigate("/registracija")}>Register</span>
              <span className="btnNav" onClick={() => navigate("/login")}>Login</span>
            </>
          )}
        </div>
      </nav>
    </header>
  );
}
